// Ransomware Group Adversary Abilities & IOC Database
// Maps each ransomware group's TTPs to executable adversary abilities with IOC metadata

export interface CalderaAbilityDef {
  ability_id: string;
  name: string;
  description: string;
  tactic: string;
  technique_id: string;
  technique_name: string;
  platforms: {
    [platform: string]: {
      [executor: string]: {
        command: string;
        cleanup?: string;
        timeout?: number;
      };
    };
  };
  singleton?: boolean;
  repeatable?: boolean;
  requirements?: { module: string; source: string }[];
}

export interface RansomwareIOC {
  type: 'hash_md5' | 'hash_sha256' | 'domain' | 'ip' | 'url' | 'email' | 'filename' | 'registry' | 'mutex' | 'user_agent';
  value: string;
  description: string;
  confidence: 'high' | 'medium' | 'low';
  firstSeen?: string;
  lastSeen?: string;
}

export interface RansomwareAbilityProfile {
  groupId: string;
  groupName: string;
  adversaryId: string;
  description: string;
  abilities: CalderaAbilityDef[];
  iocs: RansomwareIOC[];
  killChainPhases: string[];
}

