// Helper: Get all abilities for a specific group
export function getAbilitiesForGroup(groupId: string): CalderaAbilityDef[] {
  return RANSOMWARE_PROFILES.find(p => p.groupId === groupId)?.abilities || [];
}

// Helper: Get all IOCs for a specific group
export function getIOCsForGroup(groupId: string): RansomwareIOC[] {
  return RANSOMWARE_PROFILES.find(p => p.groupId === groupId)?.iocs || [];
}

// Helper: Get all abilities across all groups
export function getAllAbilities(): CalderaAbilityDef[] {
  return RANSOMWARE_PROFILES.flatMap(p => p.abilities);
}

// Helper: Get all IOCs across all groups
export function getAllIOCs(): RansomwareIOC[] {
  return RANSOMWARE_PROFILES.flatMap(p => p.iocs);
}

// Helper: Get abilities by tactic across all groups
export function getAbilitiesByTactic(tactic: string): CalderaAbilityDef[] {
  return getAllAbilities().filter(a => a.tactic === tactic);
}

// Helper: Search IOCs by value pattern
export function searchIOCs(pattern: string): RansomwareIOC[] {
  const lower = pattern.toLowerCase();
  return getAllIOCs().filter(ioc => 
    (ioc.value || '').toLowerCase().includes(lower) || 
    (ioc.description || '').toLowerCase().includes(lower)
  );
}

// Total counts for dashboard display
export const RANSOMWARE_STATS = {
  totalGroups: RANSOMWARE_PROFILES.length,
  totalAbilities: getAllAbilities().length,
  totalIOCs: getAllIOCs().length,
  totalTactics: new Set(getAllAbilities().map(a => a.tactic)).size,
};
